const n = [];
for (let i = 1; i <= 25; i += 0.5) n.push(i);

const o1 = n.map(() => 1);
const oLogN = n.map(v => Math.log2(v));
const oN = n.map(v => v);
const oNLogN = n.map(v => v * Math.log2(v));
const oN2 = n.map(v => Math.pow(v, 2));
const o2N = n.map(v => Math.pow(2, v));

const common = { mode: 'lines', line: { width: 3 } };

return [
  { ...common, x: n, y: o1, name: 'O(1) - Constant', line: { color: '#94a3b8', width: 2 } },
  { ...common, x: n, y: oLogN, name: 'O(log n) - Logarithmic', line: { color: '#10b981' } },
  { ...common, x: n, y: oN, name: 'O(n) - Linear', line: { color: '#3b82f6' } },
  { ...common, x: n, y: oNLogN, name: 'O(n log n) - Linearithmic', line: { color: '#8b5cf6' } },
  { ...common, x: n, y: oN2, name: 'O(n²) - Quadratic', line: { color: '#f59e0b' } },
  { ...common, x: n, y: o2N, name: 'O(2ⁿ) - Exponential', line: { color: '#ef4444' } }
];
